UIListener = {}

function UIListener:init()
    Listener.registerCallBack(CastLuaStringEvent, self.onCastLuaString)
    Listener.registerCallBack(ParseUI64Event, self.onParseUI64)
end

function UIListener.onCastLuaString(input, result)
    result.value = Utility.toKMBString(input, 4)
    --LogUtil.log("onCastLuaString " .. result.value)
end

function UIListener.onParseUI64(str, result)
    result.value = Utility.kmbStrToNumber(str)
    LogUtil.log("onParseUI64 " .. tostring(result.value))
end

return UIListener